query getAppStatistics($countryCode: String!) {
  getAppStatistics(payload: {countryCode: $countryCode, type: "CONVERSIONS"}) {
    _id
    last90Days {
      currencies {
        baseValue
        rateValue
        rateCurrencyCode
        type
        usesRateValue
        __typename
      }
      date
      __typename
    }
    last365Days {
      currencies {
        baseValue
        rateValue
        rateCurrencyCode
        type
        usesRateValue
        __typename
      }
      date
      __typename
    }
    country {
      code
      dial_code
      flag
      name
      __typename
    }
    type
    createdAt
    __typename
  }
}
